#include <stdio.h>
#include <math.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long N;
        scanf("%lld", &N);
        long long ans = 0;
        for (long long X = N; X <= 1000000000000000000; X += N) {
            long long divisors = 1;
            long long temp = X;
            for (long long i = 2; i * i <= temp; i++) {
                long long count = 0;
                while (temp % i == 0) {
                    count++;
                    temp /= i;
                }
                if (count > 0) divisors *= (count + 1);
            }
            if (temp > 1) divisors *= 2;
            if (divisors == N) ans++;
            if (X > 1000000000000000000) break;
        }
        if (ans > 100) printf("-1\n");
        else printf("%lld\n", ans);
    }
    return 0;
}

