    for X in range(N, 1000000000000000001, N):
        divisors = 1
        temp = X
        for i in range(2, int(math.sqrt(temp)) + 1):
            count = 0
            while temp % i == 0:
                count += 1
                temp //= i
            if count > 0: divisors *= (count + 1)
        if temp > 1: divisors *= 2
        if divisors == N: ans += 1
        if X > 1000000000000000000: break
    if ans > 100: print(-1)
